"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[7516],{13448(n,t,r){r.r(t),r.d(t,{assets:()=>c,contentTitle:()=>a,default:()=>l,frontMatter:()=>d,metadata:()=>e,toc:()=>p});const e=JSON.parse('{"id":"cpp20/jthread","title":"jthread \u548c stop_token (\u534f\u4f5c\u5f0f\u7ebf\u7a0b\u53d6\u6d88)","description":"C++20 jthread \u548c stop_token (\u534f\u4f5c\u5f0f\u7ebf\u7a0b\u53d6\u6d88) \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp20/70-jthread.md","sourceDirName":"cpp20","slug":"/cpp20/70-jthread","permalink":"/LearnModernCpp/docs/cpp20/70-jthread","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp20","permalink":"/LearnModernCpp/docs/tags/cpp-20"},{"inline":true,"label":"jthread","permalink":"/LearnModernCpp/docs/tags/jthread"}],"version":"current","sidebarPosition":71,"frontMatter":{"sidebar_position":71,"slug":"70-jthread","title":"jthread \u548c stop_token (\u534f\u4f5c\u5f0f\u7ebf\u7a0b\u53d6\u6d88)","description":"C++20 jthread \u548c stop_token (\u534f\u4f5c\u5f0f\u7ebf\u7a0b\u53d6\u6d88) \u6559\u5b66\u793a\u4f8b","tags":["cpp20","jthread"]},"sidebar":"docs","previous":{"title":"\u5173\u8054\u5bb9\u5668 contains()","permalink":"/LearnModernCpp/docs/cpp20/47-contains"},"next":{"title":"barrier\u3001latch \u548c counting_semaphore","permalink":"/LearnModernCpp/docs/cpp20/71-barrier-latch"}}');var s=r(74848),o=r(28453);const d={sidebar_position:71,slug:"70-jthread",title:"jthread \u548c stop_token (\u534f\u4f5c\u5f0f\u7ebf\u7a0b\u53d6\u6d88)",description:"C++20 jthread \u548c stop_token (\u534f\u4f5c\u5f0f\u7ebf\u7a0b\u53d6\u6d88) \u6559\u5b66\u793a\u4f8b",tags:["cpp20","jthread"]},a="jthread \u548c stop_token (\u534f\u4f5c\u5f0f\u7ebf\u7a0b\u53d6\u6d88)",c={},p=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function i(n){const t={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,o.R)(),...n.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.header,{children:(0,s.jsx)(t.h1,{id:"jthread-\u548c-stop_token-\u534f\u4f5c\u5f0f\u7ebf\u7a0b\u53d6\u6d88",children:"jthread \u548c stop_token (\u534f\u4f5c\u5f0f\u7ebf\u7a0b\u53d6\u6d88)"})}),"\n",(0,s.jsx)(t.p,{children:"C++20 \u6807\u51c6\u5f15\u5165\u7684 jthread \u548c stop_token (\u534f\u4f5c\u5f0f\u7ebf\u7a0b\u53d6\u6d88) \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,s.jsx)(t.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{className:"language-cpp",metastring:'title="cpp20/70_jthread.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: jthread \u548c stop_token (\u534f\u4f5c\u5f0f\u7ebf\u7a0b\u53d6\u6d88)\r\n * \u6240\u5c5e\u6807\u51c6: C++20\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: std::jthread \u662f std::thread \u7684\u6539\u8fdb\u7248\u672c\uff0c\r\n *          \u652f\u6301 RAII \u81ea\u52a8 join \u548c\u534f\u4f5c\u5f0f\u53d6\u6d88\u673a\u5236\uff08stop_token\uff09\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: std::thread \u6709\u4e24\u4e2a\u75db\u70b9\uff1a\r\n *             1) \u6790\u6784\u65f6\u5982\u679c\u7ebf\u7a0b\u8fd8\u5728\u8fd0\u884c\u4f1a\u8c03\u7528 std::terminate\r\n *             2) \u6ca1\u6709\u6807\u51c6\u7684\u7ebf\u7a0b\u53d6\u6d88\u673a\u5236\r\n *             jthread \u540c\u65f6\u89e3\u51b3\u4e86\u8fd9\u4e24\u4e2a\u95ee\u9898\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - jthread \u6790\u6784\u65f6\u81ea\u52a8\u8bf7\u6c42\u505c\u6b62\u5e76 join\uff08RAII\uff09\r\n *   - stop_token \u63d0\u4f9b\u534f\u4f5c\u5f0f\u53d6\u6d88\u673a\u5236\r\n *   - stop_callback \u5728\u6536\u5230\u505c\u6b62\u8bf7\u6c42\u65f6\u6267\u884c\u56de\u8c03\r\n *   - \u7ebf\u7a0b\u51fd\u6570\u53ef\u4ee5\u63a5\u6536 stop_token \u4f5c\u4e3a\u7b2c\u4e00\u4e2a\u53c2\u6570\r\n * ============================================================\r\n */\r\n\r\n#include <chrono>\r\n#include <functional>\r\n#include <iostream>\r\n#include <mutex>\r\n#include <string>\r\n#include <thread>\r\n#include <vector>\r\n\r\n// \u7528\u4e8e\u540c\u6b65\u8f93\u51fa\u7684\u4e92\u65a5\u9501\r\nstd::mutex cout_mutex;\r\n\r\nvoid safe_print(const std::string& msg) {\r\n    std::lock_guard lock(cout_mutex);\r\n    std::cout << msg << "\\n";\r\n}\r\n\r\n// ===================== basic_usage() =====================\r\nvoid basic_usage() {\r\n    std::cout << "--- \u57fa\u7840\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // 1. jthread \u81ea\u52a8 join\uff08RAII\uff09\r\n    std::cout << "-- jthread \u81ea\u52a8 join --\\n";\r\n    {\r\n        std::jthread t([] {\r\n            safe_print("  [jthread] \u5de5\u4f5c\u7ebf\u7a0b\u5f00\u59cb\u6267\u884c");\r\n            std::this_thread::sleep_for(std::chrono::milliseconds(100));\r\n            safe_print("  [jthread] \u5de5\u4f5c\u7ebf\u7a0b\u6267\u884c\u5b8c\u6bd5");\r\n        });\r\n        // \u4e0d\u9700\u8981\u663e\u5f0f\u8c03\u7528 t.join()!\r\n        // jthread \u6790\u6784\u65f6\u4f1a\u81ea\u52a8 join\r\n        safe_print("  [\u4e3b\u7ebf\u7a0b] \u5373\u5c06\u79bb\u5f00\u4f5c\u7528\u57df...");\r\n    }\r\n    // \u5230\u8fd9\u91cc jthread \u6790\u6784\uff0c\u81ea\u52a8\u7b49\u5f85\u7ebf\u7a0b\u7ed3\u675f\r\n    std::cout << "  [\u4e3b\u7ebf\u7a0b] \u5df2\u5b89\u5168\u9000\u51fa\u4f5c\u7528\u57df\\n";\r\n\r\n    // \u5bf9\u6bd4\uff1astd::thread \u5fc5\u987b\u663e\u5f0f join\r\n    std::cout << "\\n-- \u5bf9\u6bd4 std::thread --\\n";\r\n    {\r\n        std::thread t([] {\r\n            safe_print("  [thread] \u5de5\u4f5c\u7ebf\u7a0b\u6267\u884c");\r\n        });\r\n        t.join();  // \u5fc5\u987b\u663e\u5f0f join\uff0c\u5426\u5219\u6790\u6784\u65f6 terminate!\r\n        std::cout << "  [\u4e3b\u7ebf\u7a0b] std::thread \u5fc5\u987b\u663e\u5f0f join\\n";\r\n    }\r\n\r\n    // 2. stop_token \u53d6\u6d88\u673a\u5236\r\n    std::cout << "\\n-- stop_token \u53d6\u6d88\u673a\u5236 --\\n";\r\n    {\r\n        // \u7ebf\u7a0b\u51fd\u6570\u7684\u7b2c\u4e00\u4e2a\u53c2\u6570\u5982\u679c\u662f stop_token\uff0cjthread \u4f1a\u81ea\u52a8\u4f20\u5165\r\n        std::jthread worker([](std::stop_token stoken) {\r\n            int count = 0;\r\n            while (!stoken.stop_requested()) {\r\n                safe_print("  [\u5de5\u4f5c\u7ebf\u7a0b] \u6b63\u5728\u5de5\u4f5c... (" + std::to_string(++count) + ")");\r\n                std::this_thread::sleep_for(std::chrono::milliseconds(50));\r\n            }\r\n            safe_print("  [\u5de5\u4f5c\u7ebf\u7a0b] \u6536\u5230\u505c\u6b62\u8bf7\u6c42\uff0c\u4f18\u96c5\u9000\u51fa");\r\n        });\r\n\r\n        std::this_thread::sleep_for(std::chrono::milliseconds(200));\r\n        std::cout << "  [\u4e3b\u7ebf\u7a0b] \u53d1\u9001\u505c\u6b62\u8bf7\u6c42\\n";\r\n        worker.request_stop();  // \u8bf7\u6c42\u7ebf\u7a0b\u505c\u6b62\r\n        // jthread \u6790\u6784\u65f6\u4e5f\u4f1a\u81ea\u52a8 request_stop + join\r\n    }\r\n    std::cout << "  [\u4e3b\u7ebf\u7a0b] \u5de5\u4f5c\u7ebf\u7a0b\u5df2\u505c\u6b62\\n";\r\n}\r\n\r\n// ===================== advanced_usage() =====================\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- \u9ad8\u7ea7\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // 1. stop_callback: \u505c\u6b62\u65f6\u7684\u56de\u8c03\r\n    std::cout << "-- stop_callback --\\n";\r\n    {\r\n        std::jthread worker([](std::stop_token stoken) {\r\n            // \u6ce8\u518c\u505c\u6b62\u56de\u8c03\r\n            std::stop_callback callback(stoken, [] {\r\n                safe_print("  [\u56de\u8c03] \u505c\u6b62\u56de\u8c03\u88ab\u89e6\u53d1!");\r\n            });\r\n\r\n            while (!stoken.stop_requested()) {\r\n                std::this_thread::sleep_for(std::chrono::milliseconds(50));\r\n            }\r\n            safe_print("  [\u5de5\u4f5c\u7ebf\u7a0b] \u9000\u51fa");\r\n        });\r\n\r\n        std::this_thread::sleep_for(std::chrono::milliseconds(100));\r\n        std::cout << "  [\u4e3b\u7ebf\u7a0b] \u8bf7\u6c42\u505c\u6b62...\\n";\r\n        worker.request_stop();\r\n    }\r\n\r\n    // 2. stop_source: \u624b\u52a8\u63a7\u5236\u505c\u6b62\r\n    std::cout << "\\n-- stop_source --\\n";\r\n    {\r\n        std::stop_source ssource;\r\n        std::stop_token stoken = ssource.get_token();\r\n\r\n        std::jthread t1([stoken] {\r\n            while (!stoken.stop_requested()) {\r\n                std::this_thread::sleep_for(std::chrono::milliseconds(30));\r\n            }\r\n            safe_print("  [\u7ebf\u7a0b1] \u5df2\u505c\u6b62");\r\n        });\r\n\r\n        std::jthread t2([stoken] {\r\n            while (!stoken.stop_requested()) {\r\n                std::this_thread::sleep_for(std::chrono::milliseconds(30));\r\n            }\r\n            safe_print("  [\u7ebf\u7a0b2] \u5df2\u505c\u6b62");\r\n        });\r\n\r\n        std::this_thread::sleep_for(std::chrono::milliseconds(100));\r\n        std::cout << "  [\u4e3b\u7ebf\u7a0b] \u901a\u8fc7 stop_source \u540c\u65f6\u505c\u6b62\u4e24\u4e2a\u7ebf\u7a0b\\n";\r\n        ssource.request_stop();  // \u4e00\u6b21\u8bf7\u6c42\u505c\u6b62\u6240\u6709\u6301\u6709 token \u7684\u7ebf\u7a0b\r\n    }\r\n\r\n    // 3. \u83b7\u53d6 jthread \u7684 stop_source\r\n    std::cout << "\\n-- \u83b7\u53d6 jthread \u7684 stop_source --\\n";\r\n    {\r\n        std::jthread worker([](std::stop_token stoken) {\r\n            int i = 0;\r\n            while (!stoken.stop_requested()) {\r\n                safe_print("  [\u5de5\u4f5c] \u8fed\u4ee3 " + std::to_string(++i));\r\n                std::this_thread::sleep_for(std::chrono::milliseconds(50));\r\n            }\r\n        });\r\n\r\n        // \u83b7\u53d6 jthread \u5185\u90e8\u7684 stop_source\r\n        auto source = worker.get_stop_source();\r\n        auto token = worker.get_stop_token();\r\n\r\n        std::cout << "  stop_possible: " << std::boolalpha << token.stop_possible() << "\\n";\r\n\r\n        std::this_thread::sleep_for(std::chrono::milliseconds(150));\r\n        source.request_stop();\r\n        std::cout << "  stop_requested: " << token.stop_requested() << "\\n";\r\n    }\r\n\r\n    // 4. \u591a\u4e2a stop_callback\r\n    std::cout << "\\n-- \u591a\u4e2a stop_callback --\\n";\r\n    {\r\n        std::jthread worker([](std::stop_token stoken) {\r\n            std::stop_callback cb1(stoken, [] {\r\n                safe_print("  [\u56de\u8c031] \u4fdd\u5b58\u72b6\u6001...");\r\n            });\r\n            std::stop_callback cb2(stoken, [] {\r\n                safe_print("  [\u56de\u8c032] \u91ca\u653e\u8d44\u6e90...");\r\n            });\r\n            std::stop_callback cb3(stoken, [] {\r\n                safe_print("  [\u56de\u8c033] \u53d1\u9001\u901a\u77e5...");\r\n            });\r\n\r\n            while (!stoken.stop_requested()) {\r\n                std::this_thread::sleep_for(std::chrono::milliseconds(50));\r\n            }\r\n            safe_print("  [\u5de5\u4f5c\u7ebf\u7a0b] \u9000\u51fa");\r\n        });\r\n\r\n        std::this_thread::sleep_for(std::chrono::milliseconds(100));\r\n        worker.request_stop();\r\n    }\r\n\r\n    // 5. jthread \u4e0e std::thread \u7684\u63a5\u53e3\u517c\u5bb9\r\n    std::cout << "\\n-- jthread \u5176\u4ed6\u63a5\u53e3 --\\n";\r\n    {\r\n        std::jthread t([] {\r\n            std::this_thread::sleep_for(std::chrono::milliseconds(10));\r\n        });\r\n        std::cout << "  \u7ebf\u7a0b ID: " << t.get_id() << "\\n";\r\n        std::cout << "  joinable: " << std::boolalpha << t.joinable() << "\\n";\r\n        std::cout << "  hardware_concurrency: " << std::jthread::hardware_concurrency() << "\\n";\r\n    }\r\n}\r\n\r\n// ===================== pitfalls() =====================\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- \u6613\u9519\u70b9 ---\\n\\n";\r\n\r\n    // \u9677\u96311\uff1astop_token \u662f\u534f\u4f5c\u5f0f\u7684\r\n    std::cout << "1. stop_token \u662f\u534f\u4f5c\u5f0f\u53d6\u6d88\uff0c\u7ebf\u7a0b\u5fc5\u987b\u4e3b\u52a8\u68c0\u67e5:\\n";\r\n    std::cout << "   \u4e0d\u4f1a\u5f3a\u5236\u7ec8\u6b62\u7ebf\u7a0b\uff08\u4e0d\u662f pthread_cancel\uff09\\n";\r\n    std::cout << "   \u7ebf\u7a0b\u5fc5\u987b\u5728\u5faa\u73af\u4e2d\u68c0\u67e5 stop_requested()\\n";\r\n    std::cout << "   \u5982\u679c\u7ebf\u7a0b\u5728\u963b\u585e\u64cd\u4f5c\u4e2d\uff0c\u4e0d\u4f1a\u81ea\u52a8\u5524\u9192\\n\\n";\r\n\r\n    // \u9677\u96312\uff1ajthread \u6790\u6784\u987a\u5e8f\r\n    std::cout << "2. jthread \u6790\u6784\u65f6\u5148 request_stop()\uff0c\u518d join():\\n";\r\n    std::cout << "   \u5982\u679c\u7ebf\u7a0b\u4e0d\u68c0\u67e5 stop_token\uff0cjoin \u4f1a\u4e00\u76f4\u7b49\u5f85\\n";\r\n    std::cout << "   \u76f8\u5f53\u4e8e\u548c std::thread \u4e0d join \u540c\u6837\u7684\u6b7b\u9501\u98ce\u9669\\n\\n";\r\n\r\n    // \u9677\u96313\uff1astop_callback \u7684\u751f\u547d\u5468\u671f\r\n    std::cout << "3. stop_callback \u5728\u6790\u6784\u65f6\u81ea\u52a8\u6ce8\u9500:\\n";\r\n    std::cout << "   \u5982\u679c callback \u5bf9\u8c61\u5148\u4e8e stop \u8bf7\u6c42\u6790\u6784\uff0c\u56de\u8c03\u4e0d\u4f1a\u6267\u884c\\n";\r\n    std::cout << "   \u786e\u4fdd callback \u5bf9\u8c61\u7684\u751f\u547d\u5468\u671f\u8986\u76d6\u9700\u8981\u7684\u8303\u56f4\\n\\n";\r\n\r\n    // \u9677\u96314\uff1a\u4e0d\u80fd detach \u540e\u518d request_stop\r\n    std::cout << "4. detach \u540e\u4e0d\u80fd\u518d request_stop:\\n";\r\n    std::cout << "   jthread \u652f\u6301 detach()\uff0c\u4f46 detach \u540e stop_source \u5931\u6548\\n";\r\n    std::cout << "   \u901a\u5e38\u4e0d\u5efa\u8bae\u5bf9 jthread \u4f7f\u7528 detach\\n\\n";\r\n\r\n    // \u9677\u96315\uff1astop_callback \u7684\u7ebf\u7a0b\u5b89\u5168\r\n    std::cout << "5. stop_callback \u6267\u884c\u7684\u7ebf\u7a0b:\\n";\r\n    std::cout << "   \u5982\u679c\u6ce8\u518c\u65f6\u5df2\u7ecf stop_requested\uff0c\u56de\u8c03\u5728\u6ce8\u518c\u7ebf\u7a0b\u6267\u884c\\n";\r\n    std::cout << "   \u5982\u679c\u6ce8\u518c\u540e\u624d stop_requested\uff0c\u56de\u8c03\u5728\u8c03\u7528 request_stop \u7684\u7ebf\u7a0b\u6267\u884c\\n";\r\n    std::cout << "   \u56de\u8c03\u4e2d\u8981\u6ce8\u610f\u7ebf\u7a0b\u5b89\u5168\\n";\r\n}\r\n\r\n// ===================== main() =====================\r\nint main() {\r\n    std::cout << "===== jthread \u548c stop_token - C++20 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,s.jsx)(t.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:(0,s.jsx)(t.a,{href:"https://en.cppreference.com/w/cpp/thread/thread",children:"cppreference: jthread \u548c stop_token (\u534f\u4f5c\u5f0f\u7ebf\u7a0b\u53d6\u6d88)"})}),"\n"]})]})}function l(n={}){const{wrapper:t}={...(0,o.R)(),...n.components};return t?(0,s.jsx)(t,{...n,children:(0,s.jsx)(i,{...n})}):i(n)}},28453(n,t,r){r.d(t,{R:()=>d,x:()=>a});var e=r(96540);const s={},o=e.createContext(s);function d(n){const t=e.useContext(o);return e.useMemo(function(){return"function"==typeof n?n(t):{...t,...n}},[t,n])}function a(n){let t;return t=n.disableParentContext?"function"==typeof n.components?n.components(s):n.components||s:d(n.components),e.createElement(o.Provider,{value:t},n.children)}}}]);